// Politics/Tweet event — no BS pricing, no underlying
// Twitter API returned 0 (key not configured), so estimates are based on
// market microstructure + time-decay reasoning.
//
// Context: 83% through the 48h window (8.2h remaining as of fetch)
// Market pricing implies tweet count is tracking toward 40-64 range with high confidence.
// Without direct count data, we treat market mid-prices as near-fair but look for
// bid/ask edge and any systematic mis-pricing.
//
// Probability estimates:
// The market sum across all buckets is ~1.0125, implying ~1.25% systematic overpricing
// (normal for prediction markets). We deflate each bucket's pYes proportionally.
//
// Key thesis:
// - <40: essentially impossible given 8.2h remaining + market consensus → 0.05%
// - 40-64: dominant bucket. 88% mid. Given 83% elapsed, if pace is ~50 tweets → 
//   remaining ~8-10 more → stays in range. Fair value ~87%.
// - 65-89: tail risk. 11.95% mid. With 8.2h left, pace would need to be higher 
//   than market implies. Fair value ~12.5% (slight premium — end-of-window behavior 
//   can be lumpy).
// - 90+: very unlikely, ~1% aggregate. Agree with market.

const THRESHOLD = 0.025; // tighter threshold for tweet markets (less edge available)

// Explicit pYes estimates per market question
const estimates = {
  "Will Elon Musk post <40 tweets from April 18 to April 20, 2026?": 0.0005,
  "Will Elon Musk post 40-64 tweets from April 18 to April 20, 2026?": 0.87,
  "Will Elon Musk post 65-89 tweets from April 18 to April 20, 2026?": 0.125,
  "Will Elon Musk post 90-114 tweets from April 18 to April 20, 2026?": 0.009,
  "Will Elon Musk post 115-139 tweets from April 18 to April 20, 2026?": 0.0015,
  "Will Elon Musk post 140-164 tweets from April 18 to April 20, 2026?": 0.0005,
  "Will Elon Musk post 165-189 tweets from April 18 to April 20, 2026?": 0.0005,
  "Will Elon Musk post 190-214 tweets from April 18 to April 20, 2026?": 0.0003,
  "Will Elon Musk post 215-239 tweets from April 18 to April 20, 2026?": 0.0002,
  "Will Elon Musk post 240+ tweets from April 18 to April 20, 2026?": 0.0002,
};

// Hours elapsed and remaining
const windowStartTs = new Date("2026-04-18T16:00:00Z").getTime();
const windowEndTs   = new Date("2026-04-20T16:00:00Z").getTime();
const nowTs         = ctx.timing.nowTs;
const totalHours    = (windowEndTs - windowStartTs) / 3600000;
const elapsedHours  = (nowTs - windowStartTs) / 3600000;
const remainingHours = (windowEndTs - nowTs) / 3600000;
const pctElapsed    = elapsedHours / totalHours;

return ctx.markets.map((market) => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: "hold", reason: "closed or expired" };
    }
    const mCtx = { market, timing: ctx.timing };
    const pYes = estimates[market.question] ?? 0.5;
    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, pYes);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];

    const meta = {
      question: market.question,
      expiryDate: market.expiryDate,
      midPrice: market.outcomes.find(o => o.label === "Yes")?.price,
      pYesEstimate: pYes,
      hoursToExpiry: Math.round(market.hoursToExpiry * 10) / 10,
      pctWindowElapsed: Math.round(pctElapsed * 1000) / 10 + "%",
      volume: Math.round(market.volume),
      liquidity: Math.round(market.liquidity),
    };

    if (best.edge < THRESHOLD) {
      return { ...meta, decision: "hold", edge: Math.round(best.edge * 10000) / 10000 };
    }
    return {
      ...meta,
      decision: "buy",
      side: best.label,
      fairPrice: Math.round(best.fairPrice * 10000) / 10000,
      marketPrice: Math.round(best.marketPrice * 10000) / 10000,
      edge: Math.round(best.edge * 10000) / 10000,
    };
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});
